import 'dart:math';

import 'package:flutter_fractals/features/renderer/deep_zoom_precision_policy.dart';

/// Auto-zoom configuration.
class AutoExploreConfig {
  static const double defaultMinZoom = 0.2;
  static const double defaultMaxZoom = 1e12;

  /// Minimum and maximum zoom targets for the auto cycle.
  final double minZoom;
  final double maxZoom;

  /// Peak zoom target starts from: baseZoom * [cycleMaxMultiplier], then gets
  /// clamped by smart precision limits per fractal module.
  final double cycleMaxMultiplier;

  /// Maximum zoom span per leg in log10 decades (e.g. 3.0 => up to 1000x).
  final double maxLegSpanDecades;

  /// Precision headroom under policy threshold to avoid probing unstable edges.
  final double precisionHeadroom;

  /// Duration for each zoom leg (in or out).
  final Duration travelDuration;

  /// Maximum multiplier for duration scaling on very large zoom spans.
  final double maxDurationScale;

  const AutoExploreConfig({
    this.minZoom = defaultMinZoom,
    this.maxZoom = defaultMaxZoom,
    this.cycleMaxMultiplier = 120.0,
    this.maxLegSpanDecades = 3.2,
    this.precisionHeadroom = 0.92,
    this.travelDuration = const Duration(milliseconds: 9000),
    this.maxDurationScale = 4.0,
  });
}

/// Speed bounds used by auto-explore playback.
///
/// Dart's [double.clamp] treats NaN as the upper bound. For playback speed,
/// invalid telemetry or UI state should fall back to neutral 1.0x instead of
/// silently selecting the fastest supported speed.
class AutoExploreSpeed {
  static const double min = 0.5;
  static const double neutral = 1.0;
  static const double max = 3.0;

  const AutoExploreSpeed._();

  static const int sliderDivisions = 25;

  static double normalize(double speed) {
    if (!speed.isFinite) return neutral;
    return speed.clamp(min, max);
  }
}

/// Relative epsilon used to ignore tiny user zoom corrections.
///
/// Values at or above 1.0 invert the lower comparison bound and make zoom-out
/// corrections undetectable. Keep normalization explicit so correction replay
/// tests can distinguish real deadbands from malformed inputs.
class AutoExploreRelativeEpsilon {
  static const double defaultValue = 1e-4;

  const AutoExploreRelativeEpsilon._();

  static double normalize(double epsilon) {
    if (!epsilon.isFinite || epsilon < 0.0 || epsilon >= 1.0) {
      return defaultValue;
    }
    return epsilon;
  }
}

/// Direction inferred from a user zoom correction.
class AutoExploreCorrectionDecision {
  static const double defaultRelativeEpsilon =
      AutoExploreRelativeEpsilon.defaultValue;

  /// Null means the correction is inside the deadband and should preserve the
  /// current auto-explore direction.
  final bool? zoomingInOverride;

  const AutoExploreCorrectionDecision._(this.zoomingInOverride);

  bool get changedDirection => zoomingInOverride != null;

  bool resolve({required bool currentZoomingIn}) =>
      zoomingInOverride ?? currentZoomingIn;

  factory AutoExploreCorrectionDecision.fromZooms({
    required double currentZoom,
    required double previousZoom,
    double relativeEpsilon = defaultRelativeEpsilon,
  }) {
    if (!_isUsableZoomSample(currentZoom) ||
        !_isUsableZoomSample(previousZoom)) {
      return const AutoExploreCorrectionDecision._(null);
    }

    final epsilon = AutoExploreRelativeEpsilon.normalize(relativeEpsilon);
    if (currentZoom > previousZoom * (1.0 + epsilon)) {
      return const AutoExploreCorrectionDecision._(true);
    }
    if (currentZoom < previousZoom * (1.0 - epsilon)) {
      return const AutoExploreCorrectionDecision._(false);
    }
    return const AutoExploreCorrectionDecision._(null);
  }

  static bool _isUsableZoomSample(double zoom) => zoom.isFinite && zoom > 0.0;
}

/// Replayable result of adopting a user-selected zoom into auto-explore.
///
/// The service stores several state fields while timers are active. Keeping the
/// zoom comparison and direction decision pure makes the hidden fallback order
/// testable: prefer the interaction-start zoom, otherwise the last correction
/// sample, otherwise the current zoom.
class AutoExploreZoomAdoption {
  final double currentZoom;
  final double previousZoom;
  final bool zoomingIn;
  final AutoExploreCorrectionDecision correctionDecision;

  const AutoExploreZoomAdoption({
    required this.currentZoom,
    required this.previousZoom,
    required this.zoomingIn,
    required this.correctionDecision,
  });

  factory AutoExploreZoomAdoption.fromSamples({
    required AutoExploreZoomBounds bounds,
    required double currentZoom,
    required double? referenceZoom,
    required double? lastCorrectionZoom,
    required bool wasZoomingIn,
  }) {
    final current = bounds.clamp(currentZoom);
    final previous = bounds.clamp(
      referenceZoom ?? lastCorrectionZoom ?? current,
    );
    final decision = AutoExploreCorrectionDecision.fromZooms(
      currentZoom: current,
      previousZoom: previous,
    );

    return AutoExploreZoomAdoption(
      currentZoom: current,
      previousZoom: previous,
      zoomingIn: decision.resolve(currentZoomingIn: wasZoomingIn),
      correctionDecision: decision,
    );
  }
}

/// Precision headroom used to keep auto-explore below renderer fallback edges.
///
/// Values above 1.0 would push candidates past the module precision threshold;
/// non-finite values must not rely on [double.clamp] because NaN clamps to the
/// upper bound and would silently promote targets to max zoom.
class AutoExplorePrecisionHeadroom {
  static const double neutral = 1.0;

  const AutoExplorePrecisionHeadroom._();

  static double normalize(double headroom) {
    if (!headroom.isFinite || headroom <= 0.0) return neutral;
    return headroom.clamp(0.0, neutral);
  }
}

/// Cycle shape used by auto-explore target planning.
///
/// Invalid multipliers or span limits can otherwise turn zoom-out floors into
/// max zooms or collapse peak candidates into NaN/minimum zooms. Keeping the
/// cycle shape explicit makes candidate planning replayable from config alone.
class AutoExploreCycleShape {
  final double cycleMaxMultiplier;
  final double maxLegSpanDecades;

  const AutoExploreCycleShape({
    required this.cycleMaxMultiplier,
    required this.maxLegSpanDecades,
  });

  factory AutoExploreCycleShape.fromConfig(AutoExploreConfig config) {
    return AutoExploreCycleShape(
      cycleMaxMultiplier: _finiteAtLeastNeutralOrDefault(
        config.cycleMaxMultiplier,
        const AutoExploreConfig().cycleMaxMultiplier,
      ),
      maxLegSpanDecades: _finiteNonNegativeOrDefault(
        config.maxLegSpanDecades,
        const AutoExploreConfig().maxLegSpanDecades,
      ),
    );
  }

  double get maxLegSpanRatio => pow(10.0, maxLegSpanDecades).toDouble();

  static double _finiteAtLeastNeutralOrDefault(double value, double fallback) {
    return value.isFinite && value >= 1.0 ? value : fallback;
  }

  static double _finiteNonNegativeOrDefault(double value, double fallback) {
    return value.isFinite && value >= 0.0 ? value : fallback;
  }
}

/// Duration scaling used by auto-explore zoom legs.
///
/// Invalid scale factors can otherwise flow into [double.round], where NaN or
/// infinity throws instead of producing a replayable fallback duration.
class AutoExploreDurationScale {
  static const double neutral = 1.0;

  const AutoExploreDurationScale._();

  static double normalize(double scale) {
    if (!scale.isFinite || scale < neutral) return neutral;
    return scale;
  }
}

/// Converts a zoom span into a normalized duration scale.
///
/// A leg reaches the configured maximum duration scale after this many log10
/// decades. Keeping the threshold named makes the cinematic timing assumption
/// replayable instead of burying `1.6` in duration planning.
class AutoExploreZoomSpanScale {
  static const double maxScaleSpanDecades = 1.6;

  const AutoExploreZoomSpanScale._();

  static double normalized(double spanDecades) {
    if (!spanDecades.isFinite || spanDecades <= 0.0) return 0.0;
    return (spanDecades / maxScaleSpanDecades).clamp(0.0, 1.0);
  }
}

/// Converts zoom-span scaling into a positive, finite leg duration.
///
/// This keeps duration planning replayable even when a finite-but-huge config
/// value overflows during multiplication before [double.round].
class AutoExploreLegDuration {
  // Dart Duration stores microseconds in a signed 64-bit field. Millisecond
  // candidates above this can overflow into negative durations after the
  // milliseconds-to-microseconds conversion.
  static const int _maxSafeDurationMilliseconds = 9223372036854;

  const AutoExploreLegDuration._();

  static int milliseconds({
    required Duration baseDuration,
    required double scale,
    required double speed,
  }) {
    final safeBaseMs = _safeBaseMilliseconds(baseDuration.inMilliseconds);
    if (safeBaseMs <= 0) return 1;

    final scaledMs = _finitePositiveRoundOrFallback(
      safeBaseMs * scale,
      fallback: safeBaseMs,
    );
    return max(
      1,
      _finitePositiveRoundOrFallback(
        scaledMs / AutoExploreSpeed.normalize(speed),
        fallback: safeBaseMs,
      ),
    );
  }

  static int _safeBaseMilliseconds(int baseMs) {
    if (baseMs <= 0) return 1;
    return min(baseMs, _maxSafeDurationMilliseconds);
  }

  static int _finitePositiveRoundOrFallback(
    double value, {
    required int fallback,
  }) {
    if (!value.isFinite ||
        value <= 0.0 ||
        value > _maxSafeDurationMilliseconds) {
      return fallback;
    }
    return value.round();
  }
}

/// Replayable progress for one auto-explore animation frame.
///
/// Timer-driven service code counts frames imperatively. Keeping the frame to
/// [0, 1] progress conversion pure makes off-by-one and overrun behavior
/// testable without relying on wall-clock timer order.
class AutoExploreFrameProgress {
  final int frame;
  final int totalFrames;

  const AutoExploreFrameProgress({
    required this.frame,
    required this.totalFrames,
  }) : assert(totalFrames > 0, 'totalFrames must be positive');

  double get raw {
    if (frame <= 0) return 0.0;
    return (frame / totalFrames).clamp(0.0, 1.0);
  }

  bool get reachedEnd => raw >= 1.0;
}

/// Replayable frame timing for one auto-explore zoom animation.
///
/// The service animates with a fixed frame cadence; exposing the sanitized
/// start/end zooms, duration, and frame count keeps timer-driven behavior
/// characterizable without relying on wall-clock order in service tests.
class AutoExploreFrameTiming {
  final Duration duration;
  final Duration frameInterval;

  const AutoExploreFrameTiming({
    required this.duration,
    required this.frameInterval,
  }) : assert(frameInterval > Duration.zero, 'frameInterval must be positive');

  int get totalFrames {
    final frameMicros = frameInterval.inMicroseconds;
    if (frameMicros <= 0) return 1;
    return max(1, (duration.inMicroseconds / frameMicros).round());
  }
}

/// Replayable frame timing and zoom endpoints for one auto-explore animation.
class AutoExploreZoomAnimationPlan {
  static const Duration defaultFrameInterval = Duration(milliseconds: 16);

  final double startZoom;
  final double endZoom;
  final Duration duration;
  final Duration frameInterval;

  const AutoExploreZoomAnimationPlan({
    required this.startZoom,
    required this.endZoom,
    required this.duration,
    this.frameInterval = defaultFrameInterval,
  }) : assert(frameInterval > Duration.zero, 'frameInterval must be positive');

  AutoExploreFrameTiming get frameTiming => AutoExploreFrameTiming(
        duration: duration,
        frameInterval: frameInterval,
      );

  int get totalFrames => frameTiming.totalFrames;

  AutoExploreFrameProgress progressForFrame(int frame) {
    return AutoExploreFrameProgress(
      frame: frame,
      totalFrames: totalFrames,
    );
  }

  double interpolate(double t) {
    return AutoExploreZoomInterpolation.interpolate(
      startZoom: startZoom,
      endZoom: endZoom,
      t: t,
    );
  }
}

/// Zoom bounds used by auto-explore planning.
///
/// Dart's [double.clamp] treats NaN as the upper bound, which would turn a
/// corrupted/uninitialized zoom reading into an extreme deep-zoom target.
/// Keep sanitization explicit so candidate planning remains replayable.
class AutoExploreZoomBounds {
  final double minZoom;
  final double maxZoom;

  const AutoExploreZoomBounds({
    required this.minZoom,
    required this.maxZoom,
  });

  factory AutoExploreZoomBounds.fromConfig(AutoExploreConfig config) {
    final configuredMin = _positiveFiniteOrDefault(
      config.minZoom,
      AutoExploreConfig.defaultMinZoom,
    );
    final configuredMax = _positiveFiniteOrDefault(
      config.maxZoom,
      AutoExploreConfig.defaultMaxZoom,
    );

    return AutoExploreZoomBounds(
      minZoom: min(configuredMin, configuredMax),
      maxZoom: max(configuredMin, configuredMax),
    );
  }

  static double _positiveFiniteOrDefault(double value, double fallback) {
    return value.isFinite && value > 0.0 ? value : fallback;
  }

  double clamp(double zoom) {
    if (zoom.isNaN) return minZoom;
    return zoom.clamp(minZoom, maxZoom);
  }
}

/// Replayable zoom-span math for positive, finite zoom endpoints.
///
/// Computing the ratio before taking the logarithm can overflow for valid deep
/// zoom bounds (for example `1e308 / 0.2`). Use log-space subtraction so huge
/// but finite legs still scale duration instead of looking like malformed data.
class AutoExploreZoomSpan {
  const AutoExploreZoomSpan._();

  static double decades({
    required double startZoom,
    required double endZoom,
  }) {
    final low = min(startZoom, endZoom);
    final high = max(startZoom, endZoom);
    if (low <= 0.0 || high <= low) return 0.0;

    final span = (log(high) - log(low)) / ln10;
    return span.isFinite && span > 0.0 ? span : 0.0;
  }
}

/// Sanitized zoom leg used for replayable duration/interpolation math.
class AutoExploreZoomLeg {
  final double startZoom;
  final double endZoom;

  const AutoExploreZoomLeg({
    required this.startZoom,
    required this.endZoom,
  });

  factory AutoExploreZoomLeg.fromBounds({
    required AutoExploreZoomBounds bounds,
    required double startZoom,
    required double endZoom,
  }) {
    return AutoExploreZoomLeg(
      startZoom: bounds.clamp(startZoom),
      endZoom: bounds.clamp(endZoom),
    );
  }

  double get spanDecades => AutoExploreZoomSpan.decades(
        startZoom: startZoom,
        endZoom: endZoom,
      );

  double interpolate(double t) {
    return AutoExploreZoomInterpolation.interpolate(
      startZoom: startZoom,
      endZoom: endZoom,
      t: t,
    );
  }
}

/// Numerically stable geometric interpolation for positive zoom legs.
class AutoExploreZoomInterpolation {
  const AutoExploreZoomInterpolation._();

  static double interpolate({
    required double startZoom,
    required double endZoom,
    required double t,
  }) {
    final progress = t.isNaN ? 0.0 : t.clamp(0.0, 1.0);
    if (progress <= 0.0) return startZoom;
    if (progress >= 1.0) return endZoom;

    final interpolated = exp(
      log(startZoom) + (log(endZoom) - log(startZoom)) * progress,
    );
    if (interpolated.isFinite) return interpolated;
    return progress < 0.5 ? startZoom : endZoom;
  }
}

/// Replayable peak candidate data for one auto-explore cycle step.
class AutoExplorePeakZoomCandidates {
  final double baseZoom;
  final double minProgressZoom;
  final double configuredPeakZoom;
  final double spanLimitedPeakZoom;
  final double hardMaxZoom;

  const AutoExplorePeakZoomCandidates({
    required this.baseZoom,
    required this.minProgressZoom,
    required this.configuredPeakZoom,
    required this.spanLimitedPeakZoom,
    required this.hardMaxZoom,
  });

  double get desiredPeakZoom => min(configuredPeakZoom, spanLimitedPeakZoom);

  /// The 1.25x progress nudge is a preference, not permission to violate the
  /// configured per-leg span cap or module precision hard maximum.
  double get cappedMinimumProgressZoom => min(minProgressZoom, desiredPeakZoom);

  /// Desired peak after applying the renderer precision hard maximum.
  double get precisionCappedDesiredZoom => min(desiredPeakZoom, hardMaxZoom);

  /// True when the progress nudge had to yield to the configured span cap.
  bool get minimumProgressCappedBySpan => minProgressZoom > desiredPeakZoom;

  /// True when renderer precision, not cycle shape, decides the final peak.
  bool get precisionLimited =>
      hardMaxZoom < desiredPeakZoom || hardMaxZoom < cappedMinimumProgressZoom;

  double get resolvedPeakZoom => min(
        max(cappedMinimumProgressZoom, precisionCappedDesiredZoom),
        hardMaxZoom,
      );
}

/// Replayable floor candidate data for one auto-explore cycle step.
///
/// Zoom-out floors are constrained by the same per-leg span cap as zoom-in
/// peaks. Because a floor moves toward lower zoom values, the span-limited
/// candidate is the highest allowed floor, not the lowest.
class AutoExploreFloorZoomCandidates {
  final double baseZoom;
  final double configuredFloorZoom;
  final double spanLimitedFloorZoom;

  const AutoExploreFloorZoomCandidates({
    required this.baseZoom,
    required this.configuredFloorZoom,
    required this.spanLimitedFloorZoom,
  });

  double get resolvedFloorZoom =>
      max(configuredFloorZoom, spanLimitedFloorZoom);

  /// True when the contextual cycle floor had to yield to the per-leg span cap.
  bool get floorCappedBySpan => configuredFloorZoom < spanLimitedFloorZoom;
}

/// Replayable target range for one auto-explore cycle step.
class AutoExploreZoomTargetRange {
  static const double collapseEpsilon = 1e-9;

  final double peakZoom;
  final double floorZoom;

  const AutoExploreZoomTargetRange({
    required this.peakZoom,
    required this.floorZoom,
  }) : assert(floorZoom <= peakZoom, 'floorZoom must not exceed peakZoom');

  /// Builds a target range that stays ordered after precision caps are applied.
  ///
  /// The floor candidate is derived from the cycle base, while the peak can be
  /// lowered by a module precision hard max. Without this normalization a base
  /// above the hard max makes zoom-in target a lower value than zoom-out.
  factory AutoExploreZoomTargetRange.fromCandidates({
    required double peakZoom,
    required double floorZoom,
  }) {
    return AutoExploreZoomTargetRangeResolution.fromCandidates(
      peakZoom: peakZoom,
      floorZoom: floorZoom,
    ).range;
  }

  bool get isCollapsed => (peakZoom - floorZoom).abs() < collapseEpsilon;

  double targetZoom({required bool zoomingIn}) {
    if (isCollapsed) {
      // Collapsed plans must remain inside the resolved target range. Returning
      // the cycle base can bypass a precision hard-max when floor and peak both
      // collapse below the current/base zoom.
      return min(peakZoom, floorZoom);
    }
    return zoomingIn ? peakZoom : floorZoom;
  }
}

/// Replayable ordering step for target-range candidates.
///
/// Target selection derives the peak and floor from different assumptions: the
/// peak may be lowered by module precision, while the floor comes from the cycle
/// base. This value exposes when the floor candidate had to yield to the
/// precision-capped peak instead of silently relying on `min(floor, peak)`.
class AutoExploreZoomTargetRangeResolution {
  final double requestedPeakZoom;
  final double requestedFloorZoom;
  final AutoExploreZoomTargetRange range;

  const AutoExploreZoomTargetRangeResolution({
    required this.requestedPeakZoom,
    required this.requestedFloorZoom,
    required this.range,
  });

  factory AutoExploreZoomTargetRangeResolution.fromCandidates({
    required double peakZoom,
    required double floorZoom,
  }) {
    return AutoExploreZoomTargetRangeResolution(
      requestedPeakZoom: peakZoom,
      requestedFloorZoom: floorZoom,
      range: AutoExploreZoomTargetRange(
        peakZoom: peakZoom,
        floorZoom: min(floorZoom, peakZoom),
      ),
    );
  }

  bool get floorCappedByPeak => requestedFloorZoom > range.floorZoom;
}

/// Sanitized inputs used for one replayable auto-explore target decision.
///
/// This exposes the hidden fallback order used by the service: current zoom is
/// sanitized first, then a missing cycle base adopts that sanitized current
/// value. A malformed non-null cycle base is still sanitized independently.
class AutoExploreZoomPlanInputs {
  final double currentZoom;
  final double baseZoom;

  const AutoExploreZoomPlanInputs({
    required this.currentZoom,
    required this.baseZoom,
  });

  factory AutoExploreZoomPlanInputs.fromBounds({
    required AutoExploreZoomBounds bounds,
    required double currentZoom,
    required double? cycleBaseZoom,
  }) {
    final current = bounds.clamp(currentZoom);
    return AutoExploreZoomPlanInputs(
      currentZoom: current,
      baseZoom: bounds.clamp(cycleBaseZoom ?? current),
    );
  }
}

/// Replayable target-selection data for one auto-explore cycle step.
class AutoExploreZoomTargetPlan {
  final AutoExploreZoomPlanInputs inputs;
  final AutoExplorePeakZoomCandidates peakCandidates;
  final double peakZoom;
  final double floorZoom;
  final bool zoomingIn;

  const AutoExploreZoomTargetPlan({
    required this.inputs,
    required this.peakCandidates,
    required this.peakZoom,
    required this.floorZoom,
    required this.zoomingIn,
  }) : assert(floorZoom <= peakZoom, 'floorZoom must not exceed peakZoom');

  double get currentZoom => inputs.currentZoom;
  double get baseZoom => inputs.baseZoom;

  AutoExploreZoomTargetRange get targetRange =>
      AutoExploreZoomTargetRange.fromCandidates(
        peakZoom: peakZoom,
        floorZoom: floorZoom,
      );

  bool get isCollapsed => targetRange.isCollapsed;

  bool get respectsPrecisionHardMax => peakZoom <= peakCandidates.hardMaxZoom;

  double get targetZoom => targetRange.targetZoom(zoomingIn: zoomingIn);
}

/// Pure zoom-planning logic for [AutoExploreService].
///
/// Keeping target selection side-effect free makes the precision assumptions
/// replayable in tests without constructing timers or a renderer controller.
class AutoExploreZoomPlanner {
  final AutoExploreConfig config;
  final DeepZoomPrecisionPolicy precisionPolicy;

  const AutoExploreZoomPlanner({
    required this.config,
    this.precisionPolicy = const DeepZoomPrecisionPolicy(),
  });

  AutoExploreZoomBounds get _bounds => AutoExploreZoomBounds.fromConfig(config);
  AutoExploreCycleShape get _cycleShape =>
      AutoExploreCycleShape.fromConfig(config);

  double clampZoom(double zoom) => _bounds.clamp(zoom);

  double hardMaxZoomFor(String moduleId) {
    final headroom = AutoExplorePrecisionHeadroom.normalize(
      config.precisionHeadroom,
    );
    final safeThreshold = precisionPolicy.thresholdFor(moduleId) * headroom;
    return _bounds.clamp(safeThreshold);
  }

  AutoExplorePeakZoomCandidates peakZoomCandidates({
    required double baseZoom,
    required String moduleId,
  }) {
    final base = clampZoom(baseZoom);
    final hardMax = hardMaxZoomFor(moduleId);
    final cycleShape = _cycleShape;
    final maxSpanRatio = cycleShape.maxLegSpanRatio;

    return AutoExplorePeakZoomCandidates(
      baseZoom: base,
      minProgressZoom: clampZoom(base * 1.25),
      configuredPeakZoom: clampZoom(base * cycleShape.cycleMaxMultiplier),
      spanLimitedPeakZoom: clampZoom(base * maxSpanRatio),
      hardMaxZoom: hardMax,
    );
  }

  double computePeakZoom({
    required double baseZoom,
    required String moduleId,
  }) {
    return peakZoomCandidates(
      baseZoom: baseZoom,
      moduleId: moduleId,
    ).resolvedPeakZoom;
  }

  AutoExploreFloorZoomCandidates floorZoomCandidates(double baseZoom) {
    final bounds = _bounds;
    final base = bounds.clamp(baseZoom);
    final cycleShape = _cycleShape;
    final configuredFloor = base / cycleShape.cycleMaxMultiplier;
    final spanLimitedFloor = base / cycleShape.maxLegSpanRatio;

    return AutoExploreFloorZoomCandidates(
      baseZoom: base,
      configuredFloorZoom: bounds.clamp(max(bounds.minZoom, configuredFloor)),
      spanLimitedFloorZoom: bounds.clamp(max(bounds.minZoom, spanLimitedFloor)),
    );
  }

  double computeFloorZoom(double baseZoom) {
    return floorZoomCandidates(baseZoom).resolvedFloorZoom;
  }

  AutoExploreZoomPlanInputs planInputs({
    required double currentZoom,
    required double? cycleBaseZoom,
  }) {
    return AutoExploreZoomPlanInputs.fromBounds(
      bounds: _bounds,
      currentZoom: currentZoom,
      cycleBaseZoom: cycleBaseZoom,
    );
  }

  AutoExploreZoomTargetPlan planNextTarget({
    required double currentZoom,
    required double? cycleBaseZoom,
    required bool zoomingIn,
    required String moduleId,
  }) {
    final inputs = planInputs(
      currentZoom: currentZoom,
      cycleBaseZoom: cycleBaseZoom,
    );
    final peakCandidates = peakZoomCandidates(
      baseZoom: inputs.baseZoom,
      moduleId: moduleId,
    );
    final rangeResolution = AutoExploreZoomTargetRangeResolution.fromCandidates(
      peakZoom: peakCandidates.resolvedPeakZoom,
      floorZoom: computeFloorZoom(inputs.baseZoom),
    );

    return AutoExploreZoomTargetPlan(
      inputs: inputs,
      peakCandidates: peakCandidates,
      peakZoom: rangeResolution.range.peakZoom,
      floorZoom: rangeResolution.range.floorZoom,
      zoomingIn: zoomingIn,
    );
  }

  double nextTargetZoom({
    required double currentZoom,
    required double? cycleBaseZoom,
    required bool zoomingIn,
    required String moduleId,
  }) {
    return planNextTarget(
      currentZoom: currentZoom,
      cycleBaseZoom: cycleBaseZoom,
      zoomingIn: zoomingIn,
      moduleId: moduleId,
    ).targetZoom;
  }

  AutoExploreZoomAnimationPlan animationPlanForZoomLeg({
    required double startZoom,
    required double endZoom,
    required double speed,
  }) {
    final leg = AutoExploreZoomLeg.fromBounds(
      bounds: _bounds,
      startZoom: startZoom,
      endZoom: endZoom,
    );
    final effectiveSpeed = _effectiveSpeed(speed);

    final durationScale = AutoExploreDurationScale.normalize(
      config.maxDurationScale,
    );
    final normalized = AutoExploreZoomSpanScale.normalized(leg.spanDecades);
    final scale = 1.0 + normalized * (durationScale - 1.0);

    return AutoExploreZoomAnimationPlan(
      startZoom: leg.startZoom,
      endZoom: leg.endZoom,
      duration: Duration(
        milliseconds: AutoExploreLegDuration.milliseconds(
          baseDuration: config.travelDuration,
          scale: scale,
          speed: effectiveSpeed,
        ),
      ),
    );
  }

  Duration durationForZoomLeg({
    required double startZoom,
    required double endZoom,
    required double speed,
  }) {
    return animationPlanForZoomLeg(
      startZoom: startZoom,
      endZoom: endZoom,
      speed: speed,
    ).duration;
  }

  double _effectiveSpeed(double speed) => AutoExploreSpeed.normalize(speed);

  double interpolateZoom(double start, double end, double t) {
    final leg = AutoExploreZoomLeg.fromBounds(
      bounds: _bounds,
      startZoom: start,
      endZoom: end,
    );
    return leg.interpolate(t);
  }
}

/// Side effect that [AutoExploreService.toggle] should perform for a playback
/// state snapshot.
///
/// Keeping this decision pure prevents button/sheet affordances and direct
/// service callers from drifting when auto-explore is armed but temporarily
/// yielded to user correction.
enum AutoExploreToggleTransition {
  start,
  resume,
  pause,
}

/// Pure playback-state contract for [AutoExploreService].
///
/// The service owns timers and controller side effects, but scheduling decisions
/// depend only on these flags. Keeping that contract replayable makes hidden
/// state-order assumptions testable without a wall-clock timer.
class AutoExploreRuntimeState {
  final bool isExploring;
  final bool isPaused;
  final bool isUserInteracting;
  final bool pausedByUserCorrection;

  const AutoExploreRuntimeState({
    required this.isExploring,
    required this.isPaused,
    required this.isUserInteracting,
    required this.pausedByUserCorrection,
  }) : assert(
          !pausedByUserCorrection || (isExploring && !isPaused),
          'pausedByUserCorrection is only valid while auto-explore is armed',
        );

  /// A new auto-zoom leg can start only when auto-explore owns motion.
  ///
  /// Treat [pausedByUserCorrection] as its own motion blocker instead of
  /// relying on [isUserInteracting] to also be true. That keeps release builds
  /// safe if timer callbacks observe a transient flag-order mismatch.
  bool get canScheduleZoomLeg =>
      isExploring && !isPaused && !isUserInteracting && !pausedByUserCorrection;

  /// A continuous gesture end can adopt the user-selected view only if a
  /// matching gesture start currently owns motion.
  bool get canAdoptContinuousInteractionEnd =>
      isExploring && !isPaused && isUserInteracting;

  /// An in-flight animation must stop as soon as auto-explore loses motion.
  bool get shouldInterruptAnimation => !canScheduleZoomLeg;

  /// Replayable command for the public play/pause toggle.
  AutoExploreToggleTransition get toggleTransition {
    if (!isExploring) return AutoExploreToggleTransition.start;
    if (isPaused || pausedByUserCorrection) {
      return AutoExploreToggleTransition.resume;
    }
    return AutoExploreToggleTransition.pause;
  }
}

/// Pure gate for one-shot user corrections such as mouse-wheel zooms.
///
/// Continuous gestures are already represented by [isUserInteracting] and use
/// [AutoExploreService.onUserInteractionEnd] to adopt the final zoom once. A
/// wheel/keyboard correction delivered during that gesture must not clear the
/// temporary user-correction pause early.
class AutoExploreUserCorrectionPolicy {
  const AutoExploreUserCorrectionPolicy._();

  static bool shouldAdoptOneShotCorrection(AutoExploreRuntimeState state) {
    return state.isExploring && !state.isPaused && !state.isUserInteracting;
  }
}

import 'dart:async';
import 'package:flutter/animation.dart';
import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/features/auto_explore/auto_explore_runtime_state.dart';
import 'package:flutter_fractals/features/auto_explore/auto_explore_zoom_planner.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';

export 'auto_explore_zoom_planner.dart'
    show AutoExploreConfig, AutoExploreSpeed;

/// Auto navigation mode that performs zoom-only cinematic movement.
///
/// Behavior:
/// - Slowly zooms in from the current zoom to a smart module-aware peak.
/// - Then zooms back out to a smart floor.
/// - Repeats continuously.
///
/// Pan is never modified by this service, so the user can pan freely.
class AutoExploreService extends ChangeNotifier {
  static const Cubic _cinematicCurve = Cubic(0.22, 0.0, 0.15, 1.0);

  final FractalController controller;
  final AutoExploreConfig config;
  late final AutoExploreZoomPlanner _zoomPlanner = AutoExploreZoomPlanner(
    config: config,
  );

  bool _isExploring = false;
  bool _isPaused = false;
  bool _pausedByUserCorrection = false;
  bool _isUserInteracting = false;
  double _speed = 1.0;

  Timer? _timer;
  Timer? _anim;

  double? _cycleBaseZoom;
  double? _lastCorrectionZoom;
  double? _interactionStartZoom;
  bool _zoomingIn = true;

  AutoExploreService({
    required this.controller,
    this.config = const AutoExploreConfig(),
  });

  bool get isExploring => _isExploring;
  bool get isPaused => _isPaused;

  /// True while user interaction temporarily takes control.
  bool get pausedByUserCorrection => _pausedByUserCorrection;

  double get speed => _speed;
  set speed(double v) {
    _speed = AutoExploreSpeed.normalize(v);
    notifyListeners();
  }

  void start() {
    if (_isExploring && !_isPaused) return;

    _isExploring = true;
    _isPaused = false;
    _pausedByUserCorrection = false;
    _isUserInteracting = false;
    _interactionStartZoom = null;
    _adoptCurrentZoomAsCycleBase();
    _zoomingIn = true;

    _scheduleNext();
    notifyListeners();
  }

  void pause() {
    if (!_isExploring) return;

    _isPaused = true;
    _pausedByUserCorrection = false;
    _isUserInteracting = false;
    _interactionStartZoom = null;
    _cancelScheduledMotion();
    notifyListeners();
  }

  void resume() {
    if (!_isExploring) {
      start();
      return;
    }

    _isPaused = false;
    _pausedByUserCorrection = false;
    _isUserInteracting = false;
    _interactionStartZoom = null;
    _adoptCurrentZoomAsCycleBase();
    _scheduleNext();
    notifyListeners();
  }

  /// Called when user starts a continuous gesture (drag/pinch).
  ///
  /// Auto movement is temporarily suspended so manual pan/zoom is never fought.
  void onUserInteractionStart() {
    if (!_isExploring || _isPaused) return;
    if (_isUserInteracting) return;

    _isUserInteracting = true;
    _pausedByUserCorrection = true;
    _interactionStartZoom = _clampZoom(controller.view.zoom);

    _cancelScheduledMotion();
    notifyListeners();
  }

  /// Called when user ends a continuous gesture.
  ///
  /// The user-selected zoom becomes the new baseline and auto mode continues.
  void onUserInteractionEnd() {
    if (!_runtimeState.canAdoptContinuousInteractionEnd) return;

    final referenceZoom = _interactionStartZoom;
    _isUserInteracting = false;
    _interactionStartZoom = null;

    _adoptUserViewAndContinue(referenceZoom: referenceZoom);
  }

  /// Called for one-shot user corrections (mouse wheel, keyboard, etc).
  void onUserCorrection() {
    if (!AutoExploreUserCorrectionPolicy.shouldAdoptOneShotCorrection(
      _runtimeState,
    )) {
      return;
    }
    _adoptUserViewAndContinue();
  }

  void _adoptUserViewAndContinue({double? referenceZoom}) {
    if (!_isExploring) return;

    final adoption = _adoptedZoom(referenceZoom: referenceZoom);
    _zoomingIn = adoption.zoomingIn;

    _cycleBaseZoom = adoption.currentZoom;
    _lastCorrectionZoom = adoption.currentZoom;
    _pausedByUserCorrection = false;

    // Restart leg planning from the user-selected zoom immediately.
    _cancelScheduledMotion();
    if (!_isPaused && !_isUserInteracting) {
      _scheduleNext();
    }

    notifyListeners();
  }

  void toggle() {
    switch (_runtimeState.toggleTransition) {
      case AutoExploreToggleTransition.start:
        return start();
      case AutoExploreToggleTransition.resume:
        return resume();
      case AutoExploreToggleTransition.pause:
        return pause();
    }
  }

  void stop() {
    _transitionToStopped(notify: true);
  }

  void _transitionToStopped({required bool notify}) {
    _isExploring = false;
    _isPaused = false;
    _pausedByUserCorrection = false;
    _isUserInteracting = false;
    _interactionStartZoom = null;
    _cancelScheduledMotion();
    _cycleBaseZoom = null;
    _lastCorrectionZoom = null;
    _zoomingIn = true;
    if (notify) notifyListeners();
  }

  void _cancelScheduledMotion() {
    _timer?.cancel();
    _timer = null;
    _anim?.cancel();
    _anim = null;
  }

  double _clampZoom(double z) => _zoomPlanner.clampZoom(z);

  AutoExploreRuntimeState get _runtimeState => AutoExploreRuntimeState(
        isExploring: _isExploring,
        isPaused: _isPaused,
        isUserInteracting: _isUserInteracting,
        pausedByUserCorrection: _pausedByUserCorrection,
      );

  AutoExploreZoomAdoption _adoptedZoom({double? referenceZoom}) {
    return AutoExploreZoomAdoption.fromSamples(
      bounds: AutoExploreZoomBounds.fromConfig(config),
      currentZoom: controller.view.zoom,
      referenceZoom: referenceZoom,
      lastCorrectionZoom: _lastCorrectionZoom,
      wasZoomingIn: _zoomingIn,
    );
  }

  void _adoptCurrentZoomAsCycleBase() {
    final currentZoom = _clampZoom(controller.view.zoom);
    _cycleBaseZoom = currentZoom;
    _lastCorrectionZoom = currentZoom;
  }

  double _nextTargetZoom() {
    final current = _clampZoom(controller.view.zoom);
    _cycleBaseZoom ??= current;

    // Direction is flipped only after a leg actually reaches its target.
    // This prevents user pan interruptions from resuming in the opposite
    // direction (the reported "reverse" behavior).
    return _zoomPlanner.nextTargetZoom(
      currentZoom: current,
      cycleBaseZoom: _cycleBaseZoom,
      zoomingIn: _zoomingIn,
      moduleId: controller.module.id,
    );
  }

  void _scheduleNext() {
    _timer?.cancel();
    _timer = null;
    if (!_runtimeState.canScheduleZoomLeg) return;

    // Continuous mode: no dwell/pause between zoom-in and zoom-out legs.
    _timer = Timer(Duration.zero, () async {
      if (!_runtimeState.canScheduleZoomLeg) return;

      final targetZoom = _nextTargetZoom();
      final reachedTarget = await _animateZoomTo(targetZoom);

      if (!_runtimeState.canScheduleZoomLeg) return;
      if (reachedTarget) {
        _zoomingIn = !_zoomingIn;
      }
      _scheduleNext();
    });
  }

  Future<bool> _animateZoomTo(double targetZoom) async {
    _anim?.cancel();
    _anim = null;

    final plan = _zoomPlanner.animationPlanForZoomLeg(
      startZoom: controller.view.zoom,
      endZoom: targetZoom,
      speed: _speed,
    );
    var step = 0;

    final completer = Completer<bool>();
    _anim = Timer.periodic(plan.frameInterval, (timer) {
      if (_runtimeState.shouldInterruptAnimation) {
        timer.cancel();
        _anim = null;
        if (!completer.isCompleted) completer.complete(false);
        return;
      }

      step++;
      final progress = plan.progressForFrame(step);
      final eased = _cinematicCurve.transform(progress.raw);

      controller.updateZoom(plan.interpolate(eased));
      _lastCorrectionZoom = _clampZoom(controller.view.zoom);

      if (progress.reachedEnd) {
        timer.cancel();
        _anim = null;
        if (!completer.isCompleted) completer.complete(true);
      }
    });

    return completer.future;
  }

  @override
  void dispose() {
    _transitionToStopped(notify: false);
    super.dispose();
  }
}

import 'package:flutter_fractals/features/auto_explore/auto_explore_zoom_planner.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('AutoExploreCorrectionDecision', () {
    test('maps visible zoom changes to the next leg direction', () {
      expect(
        AutoExploreCorrectionDecision.fromZooms(
          currentZoom: 10.002,
          previousZoom: 10.0,
        ).resolve(currentZoomingIn: false),
        isTrue,
      );
      expect(
        AutoExploreCorrectionDecision.fromZooms(
          currentZoom: 9.998,
          previousZoom: 10.0,
        ).resolve(currentZoomingIn: true),
        isFalse,
      );
    });

    test('preserves current direction inside the correction deadband', () {
      final decision = AutoExploreCorrectionDecision.fromZooms(
        currentZoom: 10.0005,
        previousZoom: 10.0,
      );

      expect(decision.changedDirection, isFalse);
      expect(decision.resolve(currentZoomingIn: true), isTrue);
      expect(decision.resolve(currentZoomingIn: false), isFalse);
    });

    test('normalizes malformed correction epsilon', () {
      final decision = AutoExploreCorrectionDecision.fromZooms(
        currentZoom: 10.0005,
        previousZoom: 10.0,
        relativeEpsilon: double.nan,
      );

      expect(decision.changedDirection, isFalse);
      expect(AutoExploreRelativeEpsilon.normalize(-0.1), 1e-4);
      expect(AutoExploreRelativeEpsilon.normalize(double.infinity), 1e-4);
    });

    test('normalizes correction epsilon before it hides zoom-out intent', () {
      final decision = AutoExploreCorrectionDecision.fromZooms(
        currentZoom: 5.0,
        previousZoom: 10.0,
        relativeEpsilon: 1.5,
      );

      expect(AutoExploreRelativeEpsilon.normalize(1.5), 1e-4);
      expect(decision.changedDirection, isTrue);
      expect(decision.resolve(currentZoomingIn: true), isFalse);
    });

    test('preserves direction when correction zoom samples are unusable', () {
      for (final sample in [
        (currentZoom: double.nan, previousZoom: 10.0),
        (currentZoom: double.infinity, previousZoom: 10.0),
        (currentZoom: 10.0, previousZoom: double.nan),
        (currentZoom: 10.0, previousZoom: double.infinity),
        (currentZoom: 10.0, previousZoom: 0.0),
      ]) {
        final decision = AutoExploreCorrectionDecision.fromZooms(
          currentZoom: sample.currentZoom,
          previousZoom: sample.previousZoom,
        );

        expect(
          decision.changedDirection,
          isFalse,
          reason:
              'current=${sample.currentZoom}, previous=${sample.previousZoom}',
        );
        expect(decision.resolve(currentZoomingIn: true), isTrue);
        expect(decision.resolve(currentZoomingIn: false), isFalse);
      }
    });

    test('replays user zoom adoption fallback order', () {
      const bounds = AutoExploreZoomBounds(minZoom: 0.2, maxZoom: 100.0);

      final interactionAdoption = AutoExploreZoomAdoption.fromSamples(
        bounds: bounds,
        currentZoom: 20.0,
        referenceZoom: 30.0,
        lastCorrectionZoom: 10.0,
        wasZoomingIn: true,
      );
      final correctionAdoption = AutoExploreZoomAdoption.fromSamples(
        bounds: bounds,
        currentZoom: 8.0,
        referenceZoom: null,
        lastCorrectionZoom: 10.0,
        wasZoomingIn: true,
      );
      final noHistoryAdoption = AutoExploreZoomAdoption.fromSamples(
        bounds: bounds,
        currentZoom: double.nan,
        referenceZoom: null,
        lastCorrectionZoom: null,
        wasZoomingIn: false,
      );

      expect(interactionAdoption.previousZoom, 30.0);
      expect(interactionAdoption.zoomingIn, isFalse);
      expect(correctionAdoption.previousZoom, 10.0);
      expect(correctionAdoption.zoomingIn, isFalse);
      expect(noHistoryAdoption.currentZoom, bounds.minZoom);
      expect(noHistoryAdoption.previousZoom, bounds.minZoom);
      expect(noHistoryAdoption.zoomingIn, isFalse);
      expect(noHistoryAdoption.correctionDecision.changedDirection, isFalse);
    });
  });

  group('AutoExploreZoomSpanScale', () {
    test('makes the cinematic duration span threshold explicit', () {
      expect(AutoExploreZoomSpanScale.normalized(double.nan), 0.0);
      expect(AutoExploreZoomSpanScale.normalized(-1.0), 0.0);
      expect(AutoExploreZoomSpanScale.normalized(0.8), 0.5);
      expect(AutoExploreZoomSpanScale.normalized(1.6), 1.0);
      expect(AutoExploreZoomSpanScale.normalized(3.2), 1.0);
    });
  });

  group('AutoExploreZoomPlanner', () {
    const planner = AutoExploreZoomPlanner(config: AutoExploreConfig());

    test('keeps peak zoom under module precision headroom', () {
      // Unknown modules use the default 1e7 precision threshold, so headroom is
      // 9.2e6. A base zoom near that edge used to let the 1.25x minimum peak
      // overrun the module-aware hard max.
      const moduleId = 'unknown_orbit_module';
      const baseZoom = 9.0e6;

      final hardMax = planner.hardMaxZoomFor(moduleId);
      final peakZoom = planner.computePeakZoom(
        baseZoom: baseZoom,
        moduleId: moduleId,
      );

      final candidates = planner.peakZoomCandidates(
        baseZoom: baseZoom,
        moduleId: moduleId,
      );

      expect(hardMax, 9.2e6);
      expect(candidates.precisionCappedDesiredZoom, hardMax);
      expect(candidates.precisionLimited, isTrue);
      expect(peakZoom, hardMax);
      expect(peakZoom, lessThanOrEqualTo(hardMax));
    });

    test('does not promote invalid precision headroom to max zoom', () {
      const planner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(precisionHeadroom: double.nan),
      );

      expect(planner.hardMaxZoomFor('unknown_orbit_module'), 1e7);
      expect(
        planner.computePeakZoom(
          baseZoom: 9.0e6,
          moduleId: 'unknown_orbit_module',
        ),
        lessThanOrEqualTo(1e7),
      );
    });

    test('plans zoom-in and zoom-out targets from the same cycle base', () {
      const baseZoom = 10.0;

      final zoomInPlan = planner.planNextTarget(
        currentZoom: 12.0,
        cycleBaseZoom: baseZoom,
        zoomingIn: true,
        moduleId: 'mandelbrot',
      );
      final zoomOutPlan = planner.planNextTarget(
        currentZoom: 12.0,
        cycleBaseZoom: baseZoom,
        zoomingIn: false,
        moduleId: 'mandelbrot',
      );

      expect(zoomInPlan.currentZoom, 12.0);
      expect(zoomInPlan.baseZoom, baseZoom);
      expect(zoomInPlan.peakZoom, 1200.0);
      expect(zoomInPlan.floorZoom, AutoExploreConfig().minZoom);
      expect(zoomInPlan.targetZoom, 1200.0);
      expect(zoomOutPlan.targetZoom, AutoExploreConfig().minZoom);
      expect(
        planner.nextTargetZoom(
          currentZoom: 12.0,
          cycleBaseZoom: baseZoom,
          zoomingIn: true,
          moduleId: 'mandelbrot',
        ),
        zoomInPlan.targetZoom,
      );
    });

    test('exposes sanitized target planning inputs', () {
      final missingBaseInputs = planner.planInputs(
        currentZoom: double.nan,
        cycleBaseZoom: null,
      );
      final malformedBaseInputs = planner.planInputs(
        currentZoom: 10.0,
        cycleBaseZoom: double.nan,
      );

      expect(missingBaseInputs.currentZoom, AutoExploreConfig().minZoom);
      expect(missingBaseInputs.baseZoom, missingBaseInputs.currentZoom);
      expect(malformedBaseInputs.currentZoom, 10.0);
      expect(malformedBaseInputs.baseZoom, AutoExploreConfig().minZoom);
    });

    test('makes collapsed target plans explicit', () {
      const collapsedPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(minZoom: 1.0, maxZoom: 1.0),
      );

      final plan = collapsedPlanner.planNextTarget(
        currentZoom: 42.0,
        cycleBaseZoom: null,
        zoomingIn: true,
        moduleId: 'unknown_orbit_module',
      );

      expect(plan.currentZoom, 1.0);
      expect(plan.baseZoom, 1.0);
      expect(plan.peakZoom, 1.0);
      expect(plan.floorZoom, 1.0);
      expect(plan.isCollapsed, isTrue);
      expect(plan.targetRange.targetZoom(zoomingIn: false), 1.0);
      expect(plan.targetZoom, 1.0);
    });

    test('collapsed target plans do not return a base above resolved range',
        () {
      const precisionCollapsedPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(minZoom: 1e11, maxZoom: 1e12),
      );

      final plan = precisionCollapsedPlanner.planNextTarget(
        currentZoom: 1e12,
        cycleBaseZoom: 1e12,
        zoomingIn: true,
        moduleId: 'unknown_orbit_module',
      );

      expect(plan.baseZoom, 1e12);
      expect(plan.peakZoom, 1e11);
      expect(plan.floorZoom, 1e11);
      expect(plan.isCollapsed, isTrue);
      expect(plan.targetZoom, 1e11);
      expect(
        precisionCollapsedPlanner.nextTargetZoom(
          currentZoom: 1e12,
          cycleBaseZoom: 1e12,
          zoomingIn: true,
          moduleId: 'unknown_orbit_module',
        ),
        1e11,
      );
    });

    test('orders target ranges after precision caps lower the peak', () {
      final plan = planner.planNextTarget(
        currentZoom: 1e12,
        cycleBaseZoom: 1e12,
        zoomingIn: false,
        moduleId: 'unknown_orbit_module',
      );
      final resolution = AutoExploreZoomTargetRangeResolution.fromCandidates(
        peakZoom: plan.peakCandidates.resolvedPeakZoom,
        floorZoom: planner.computeFloorZoom(plan.baseZoom),
      );

      expect(plan.peakZoom, 9.2e6);
      expect(plan.floorZoom, plan.peakZoom);
      expect(plan.isCollapsed, isTrue);
      expect(plan.targetZoom, 9.2e6);
      expect(plan.targetRange.floorZoom, lessThanOrEqualTo(plan.peakZoom));
      expect(
        resolution.requestedFloorZoom,
        moreOrLessEquals(
          1e12 / const AutoExploreConfig().cycleMaxMultiplier,
          epsilon: 1e-3,
        ),
      );
      expect(resolution.floorCappedByPeak, isTrue);
      expect(resolution.range.floorZoom, plan.peakZoom);
    });

    test('scales leg duration by zoom span and speed', () {
      const config = AutoExploreConfig(
        travelDuration: Duration(milliseconds: 1000),
        maxDurationScale: 4.0,
      );
      const fastPlanner = AutoExploreZoomPlanner(config: config);

      expect(
        fastPlanner.durationForZoomLeg(
          startZoom: 1.0,
          endZoom: 1.0,
          speed: 2.0,
        ),
        const Duration(milliseconds: 500),
      );
      expect(
        fastPlanner.durationForZoomLeg(
          startZoom: 1.0,
          endZoom: 1e6,
          speed: 2.0,
        ),
        const Duration(milliseconds: 2000),
      );
    });

    test('exposes replayable animation timing for service zoom legs', () {
      const config = AutoExploreConfig(
        travelDuration: Duration(milliseconds: 1000),
        maxDurationScale: 4.0,
      );
      const planner = AutoExploreZoomPlanner(config: config);

      final plan = planner.animationPlanForZoomLeg(
        startZoom: double.nan,
        endZoom: 1e6,
        speed: 2.0,
      );

      expect(plan.startZoom, AutoExploreConfig().minZoom);
      expect(plan.endZoom, 1e6);
      expect(plan.duration, const Duration(milliseconds: 2000));
      expect(plan.frameInterval, const Duration(milliseconds: 16));
      expect(plan.totalFrames, 125);
      expect(plan.frameTiming.totalFrames, plan.totalFrames);
      expect(plan.interpolate(double.nan), plan.startZoom);
      expect(plan.interpolate(1.0), plan.endZoom);
    });

    test('exposes replayable frame progress for timer-driven animation', () {
      const config = AutoExploreConfig(
        travelDuration: Duration(milliseconds: 1000),
      );
      const planner = AutoExploreZoomPlanner(config: config);

      final plan = planner.animationPlanForZoomLeg(
        startZoom: 1.0,
        endZoom: 1.0,
        speed: 1.0,
      );

      expect(plan.totalFrames, 63);
      expect(plan.progressForFrame(0).raw, 0.0);
      expect(plan.progressForFrame(1).raw, closeTo(1 / 63, 1e-12));
      expect(plan.progressForFrame(62).reachedEnd, isFalse);
      expect(plan.progressForFrame(63).raw, 1.0);
      expect(plan.progressForFrame(63).reachedEnd, isTrue);
      expect(plan.progressForFrame(64).raw, 1.0);
      expect(plan.progressForFrame(64).reachedEnd, isTrue);
    });

    test('counts sub-millisecond frame intervals without division by zero', () {
      final timing = AutoExploreFrameTiming(
        duration: const Duration(milliseconds: 2),
        frameInterval: const Duration(microseconds: 500),
      );

      expect(timing.totalFrames, 4);
    });

    test('normalizes invalid speed candidates before duration scaling', () {
      const config = AutoExploreConfig(
        travelDuration: Duration(milliseconds: 1000),
        maxDurationScale: 4.0,
      );
      const planner = AutoExploreZoomPlanner(config: config);

      expect(AutoExploreSpeed.normalize(0.0), AutoExploreSpeed.min);
      expect(AutoExploreSpeed.normalize(double.nan), AutoExploreSpeed.neutral);
      expect(
        AutoExploreSpeed.normalize(double.infinity),
        AutoExploreSpeed.neutral,
      );
      expect(
        AutoExploreSpeed.normalize(double.negativeInfinity),
        AutoExploreSpeed.neutral,
      );

      expect(
        planner.durationForZoomLeg(
          startZoom: 1.0,
          endZoom: 1.0,
          speed: 0.0,
        ),
        const Duration(milliseconds: 2000),
      );
      expect(
        planner.durationForZoomLeg(
          startZoom: 1.0,
          endZoom: 1.0,
          speed: double.nan,
        ),
        const Duration(milliseconds: 1000),
      );
      expect(
        planner.durationForZoomLeg(
          startZoom: 1.0,
          endZoom: 1.0,
          speed: double.infinity,
        ),
        const Duration(milliseconds: 1000),
      );
    });

    test('does not treat NaN zoom as maximum zoom', () {
      const planner = AutoExploreZoomPlanner(config: AutoExploreConfig());

      expect(planner.clampZoom(double.nan), AutoExploreConfig().minZoom);
      expect(
        planner.nextTargetZoom(
          currentZoom: double.nan,
          cycleBaseZoom: null,
          zoomingIn: true,
          moduleId: 'mandelbrot',
        ),
        24.0,
      );
    });

    test('normalizes malformed zoom bounds before clamping candidates', () {
      const reversedPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(minZoom: 100.0, maxZoom: 1.0),
      );
      const invalidPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(minZoom: double.nan, maxZoom: -1.0),
      );

      expect(reversedPlanner.clampZoom(0.5), 1.0);
      expect(reversedPlanner.clampZoom(200.0), 100.0);
      expect(invalidPlanner.clampZoom(double.nan), 0.2);
      expect(invalidPlanner.clampZoom(double.infinity), 1e12);
    });

    test('uses normalized zoom bounds for precision hard max planning', () {
      const reversedPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(minZoom: 100.0, maxZoom: 1.0),
      );
      const invalidPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(minZoom: double.nan, maxZoom: -1.0),
      );

      expect(reversedPlanner.hardMaxZoomFor('unknown_orbit_module'), 100.0);
      expect(invalidPlanner.hardMaxZoomFor('unknown_orbit_module'), 9.2e6);
      expect(
        reversedPlanner.nextTargetZoom(
          currentZoom: 10.0,
          cycleBaseZoom: null,
          zoomingIn: true,
          moduleId: 'unknown_orbit_module',
        ),
        100.0,
      );
    });

    test('sanitizes invalid zoom endpoints before duration math', () {
      const config = AutoExploreConfig(
        travelDuration: Duration(milliseconds: 1000),
        maxDurationScale: 4.0,
      );
      const planner = AutoExploreZoomPlanner(config: config);

      expect(
        planner.durationForZoomLeg(
          startZoom: double.nan,
          endZoom: 1.0,
          speed: 1.0,
        ),
        const Duration(milliseconds: 2311),
      );
      expect(
        planner.durationForZoomLeg(
          startZoom: double.infinity,
          endZoom: 1.0,
          speed: 1.0,
        ),
        const Duration(milliseconds: 4000),
      );
    });

    test('keeps interpolation finite for huge but valid zoom bounds', () {
      const planner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(maxZoom: 1e308),
      );

      expect(planner.interpolateZoom(0.2, 1e308, 0.0), 0.2);
      expect(planner.interpolateZoom(0.2, 1e308, 1.0), 1e308);
      expect(
        planner.interpolateZoom(0.2, 1e308, 0.5),
        predicate<double>((value) => value.isFinite, 'finite zoom'),
      );
      expect(planner.interpolateZoom(0.2, 1e308, double.nan), 0.2);
    });

    test('scales duration for huge but finite zoom spans', () {
      const planner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(
          maxZoom: 1e308,
          travelDuration: Duration(milliseconds: 1000),
          maxDurationScale: 4.0,
        ),
      );

      expect(
        planner.durationForZoomLeg(
          startZoom: 0.2,
          endZoom: 1e308,
          speed: 1.0,
        ),
        const Duration(milliseconds: 4000),
      );
    });

    test('exposes peak target candidates for replayable span decisions', () {
      final candidates = planner.peakZoomCandidates(
        baseZoom: 10.0,
        moduleId: 'mandelbrot',
      );
      final plan = planner.planNextTarget(
        currentZoom: 10.0,
        cycleBaseZoom: 10.0,
        zoomingIn: true,
        moduleId: 'mandelbrot',
      );

      expect(candidates.baseZoom, 10.0);
      expect(candidates.minProgressZoom, 12.5);
      expect(candidates.configuredPeakZoom, 1200.0);
      expect(
        candidates.spanLimitedPeakZoom,
        moreOrLessEquals(15848.9319, epsilon: 1e-4),
      );
      expect(candidates.hardMaxZoom, 9.2e11);
      expect(candidates.desiredPeakZoom, 1200.0);
      expect(candidates.precisionCappedDesiredZoom, 1200.0);
      expect(candidates.minimumProgressCappedBySpan, isFalse);
      expect(candidates.precisionLimited, isFalse);
      expect(candidates.resolvedPeakZoom, 1200.0);
      expect(plan.peakCandidates.baseZoom, candidates.baseZoom);
      expect(plan.peakCandidates.resolvedPeakZoom, candidates.resolvedPeakZoom);
      expect(plan.peakZoom, plan.peakCandidates.resolvedPeakZoom);
      expect(plan.respectsPrecisionHardMax, isTrue);
    });

    test('does not let minimum peak nudge exceed max leg span', () {
      const zeroSpanPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(maxLegSpanDecades: 0.0),
      );

      final candidates = zeroSpanPlanner.peakZoomCandidates(
        baseZoom: 10.0,
        moduleId: 'mandelbrot',
      );

      expect(candidates.minProgressZoom, 12.5);
      expect(candidates.spanLimitedPeakZoom, 10.0);
      expect(candidates.cappedMinimumProgressZoom, 10.0);
      expect(candidates.minimumProgressCappedBySpan, isTrue);
      expect(candidates.precisionLimited, isFalse);
      expect(candidates.resolvedPeakZoom, 10.0);
      expect(
        zeroSpanPlanner.computePeakZoom(
          baseZoom: 10.0,
          moduleId: 'mandelbrot',
        ),
        10.0,
      );
    });

    test('does not let floor targets exceed max leg span', () {
      const zeroSpanPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(maxLegSpanDecades: 0.0),
      );

      final candidates = zeroSpanPlanner.floorZoomCandidates(10.0);
      final plan = zeroSpanPlanner.planNextTarget(
        currentZoom: 10.0,
        cycleBaseZoom: 10.0,
        zoomingIn: false,
        moduleId: 'mandelbrot',
      );

      expect(candidates.baseZoom, 10.0);
      expect(candidates.configuredFloorZoom, AutoExploreConfig.defaultMinZoom);
      expect(candidates.spanLimitedFloorZoom, 10.0);
      expect(candidates.floorCappedBySpan, isTrue);
      expect(candidates.resolvedFloorZoom, 10.0);
      expect(plan.floorZoom, 10.0);
      expect(plan.targetZoom, 10.0);
      expect(
        zeroSpanPlanner.computeFloorZoom(10.0),
        10.0,
      );
    });

    test('allows a neutral cycle multiplier to keep target planning stationary',
        () {
      const neutralPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(cycleMaxMultiplier: 1.0),
      );

      final plan = neutralPlanner.planNextTarget(
        currentZoom: 10.0,
        cycleBaseZoom: 10.0,
        zoomingIn: true,
        moduleId: 'mandelbrot',
      );

      expect(plan.peakCandidates.configuredPeakZoom, 10.0);
      expect(plan.peakCandidates.cappedMinimumProgressZoom, 10.0);
      expect(plan.peakZoom, 10.0);
      expect(plan.floorZoom, 10.0);
      expect(plan.targetZoom, 10.0);
      expect(
        neutralPlanner.nextTargetZoom(
          currentZoom: 10.0,
          cycleBaseZoom: 10.0,
          zoomingIn: false,
          moduleId: 'mandelbrot',
        ),
        10.0,
      );
      expect(
        AutoExploreCycleShape.fromConfig(
          const AutoExploreConfig(cycleMaxMultiplier: 1.0),
        ).cycleMaxMultiplier,
        1.0,
      );
    });

    test('normalizes invalid cycle shape before target planning', () {
      const zeroMultiplierPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(cycleMaxMultiplier: 0.0),
      );
      const nanMultiplierPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(cycleMaxMultiplier: double.nan),
      );
      const infiniteMultiplierPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(cycleMaxMultiplier: double.infinity),
      );
      const nanSpanPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(maxLegSpanDecades: double.nan),
      );

      expect(
        zeroMultiplierPlanner.nextTargetZoom(
          currentZoom: 10.0,
          cycleBaseZoom: 10.0,
          zoomingIn: false,
          moduleId: 'mandelbrot',
        ),
        AutoExploreConfig().minZoom,
      );
      for (final planner in [
        nanMultiplierPlanner,
        infiniteMultiplierPlanner,
        nanSpanPlanner,
      ]) {
        expect(
          planner.computePeakZoom(baseZoom: 10.0, moduleId: 'mandelbrot'),
          1200.0,
        );
      }

      expect(
        AutoExploreCycleShape.fromConfig(
          const AutoExploreConfig(cycleMaxMultiplier: 0.0),
        ).cycleMaxMultiplier,
        AutoExploreConfig().cycleMaxMultiplier,
      );
    });

    test('caps oversized base durations before scaling milliseconds', () {
      final milliseconds = AutoExploreLegDuration.milliseconds(
        baseDuration: const Duration(milliseconds: 9223372036855),
        scale: 1.0,
        speed: 1.0,
      );

      expect(milliseconds, 9223372036854);
    });

    test('sanitizes invalid duration scale before rounding milliseconds', () {
      const nanScalePlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1000),
          maxDurationScale: double.nan,
        ),
      );
      const infiniteScalePlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1000),
          maxDurationScale: double.infinity,
        ),
      );
      const belowNeutralScalePlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1000),
          maxDurationScale: 0.0,
        ),
      );
      const overflowingFiniteScalePlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1000),
          maxDurationScale: 1e308,
        ),
      );
      const finiteButDurationOverflowingPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1000),
          maxDurationScale: 1e16,
        ),
      );

      for (final planner in [
        nanScalePlanner,
        infiniteScalePlanner,
        belowNeutralScalePlanner,
        overflowingFiniteScalePlanner,
        finiteButDurationOverflowingPlanner,
      ]) {
        expect(
          planner.durationForZoomLeg(
            startZoom: 1.0,
            endZoom: 1e6,
            speed: 1.0,
          ),
          const Duration(milliseconds: 1000),
        );
      }
    });
  });
}

import 'package:flutter_fractals/features/auto_explore/auto_explore_runtime_state.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('AutoExploreRuntimeState', () {
    test('allows scheduling only while auto-explore owns motion', () {
      expect(
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: false,
          isUserInteracting: false,
          pausedByUserCorrection: false,
        ).canScheduleZoomLeg,
        isTrue,
      );

      for (final state in [
        const AutoExploreRuntimeState(
          isExploring: false,
          isPaused: false,
          isUserInteracting: false,
          pausedByUserCorrection: false,
        ),
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: true,
          isUserInteracting: false,
          pausedByUserCorrection: false,
        ),
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: false,
          isUserInteracting: true,
          pausedByUserCorrection: true,
        ),
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: false,
          isUserInteracting: false,
          pausedByUserCorrection: true,
        ),
      ]) {
        expect(state.canScheduleZoomLeg, isFalse);
        expect(state.shouldInterruptAnimation, isTrue);
      }
    });

    test('keeps user-correction pause as an explicit motion blocker', () {
      final yieldedWithoutInteraction = const AutoExploreRuntimeState(
        isExploring: true,
        isPaused: false,
        isUserInteracting: false,
        pausedByUserCorrection: true,
      );

      expect(yieldedWithoutInteraction.canScheduleZoomLeg, isFalse);
      expect(yieldedWithoutInteraction.shouldInterruptAnimation, isTrue);
    });

    test('adopts continuous interaction end only after a matching start', () {
      expect(
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: false,
          isUserInteracting: true,
          pausedByUserCorrection: true,
        ).canAdoptContinuousInteractionEnd,
        isTrue,
      );

      for (final state in [
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: false,
          isUserInteracting: false,
          pausedByUserCorrection: false,
        ),
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: true,
          isUserInteracting: true,
          pausedByUserCorrection: false,
        ),
        const AutoExploreRuntimeState(
          isExploring: false,
          isPaused: false,
          isUserInteracting: true,
          pausedByUserCorrection: false,
        ),
      ]) {
        expect(state.canAdoptContinuousInteractionEnd, isFalse);
      }
    });

    test('exposes replayable toggle transitions', () {
      expect(
        const AutoExploreRuntimeState(
          isExploring: false,
          isPaused: false,
          isUserInteracting: false,
          pausedByUserCorrection: false,
        ).toggleTransition,
        AutoExploreToggleTransition.start,
      );
      expect(
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: false,
          isUserInteracting: false,
          pausedByUserCorrection: false,
        ).toggleTransition,
        AutoExploreToggleTransition.pause,
      );
      expect(
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: true,
          isUserInteracting: false,
          pausedByUserCorrection: false,
        ).toggleTransition,
        AutoExploreToggleTransition.resume,
      );
      expect(
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: false,
          isUserInteracting: true,
          pausedByUserCorrection: true,
        ).toggleTransition,
        AutoExploreToggleTransition.resume,
      );
    });

    test('gates one-shot corrections while continuous gestures own motion', () {
      final idleAutoExplore = const AutoExploreRuntimeState(
        isExploring: true,
        isPaused: false,
        isUserInteracting: false,
        pausedByUserCorrection: false,
      );
      final continuousGesture = const AutoExploreRuntimeState(
        isExploring: true,
        isPaused: false,
        isUserInteracting: true,
        pausedByUserCorrection: true,
      );

      expect(
        AutoExploreUserCorrectionPolicy.shouldAdoptOneShotCorrection(
          idleAutoExplore,
        ),
        isTrue,
      );
      expect(
        AutoExploreUserCorrectionPolicy.shouldAdoptOneShotCorrection(
          continuousGesture,
        ),
        isFalse,
      );
    });

    test('characterizes user-correction pause as armed auto-explore only', () {
      expect(
        () => AutoExploreRuntimeState(
          isExploring: true,
          isPaused: true,
          isUserInteracting: false,
          pausedByUserCorrection: true,
        ),
        throwsAssertionError,
      );
      expect(
        () => AutoExploreRuntimeState(
          isExploring: false,
          isPaused: false,
          isUserInteracting: false,
          pausedByUserCorrection: true,
        ),
        throwsAssertionError,
      );
    });
  });
}

import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/features/auto_explore/auto_explore_service.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('AutoExploreService', () {
    test('dispose cancels without sending a playback update', () {
      final controller = FractalController(ModuleRegistry());
      final service = AutoExploreService(controller: controller);
      addTearDown(controller.dispose);

      var notifications = 0;
      service.addListener(() => notifications++);

      service.dispose();

      expect(notifications, 0);
    });

    test('ignores one-shot corrections during continuous user interaction',
        () async {
      final controller = FractalController(ModuleRegistry());
      controller.resetView();
      controller.updateZoom(1.0);

      final service = AutoExploreService(
        controller: controller,
        config: const AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1),
        ),
      );
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      await Future<void>.delayed(Duration.zero);
      service.onUserInteractionStart();

      expect(service.pausedByUserCorrection, isTrue);

      controller.updateZoom(2.0);
      service.onUserCorrection();

      expect(service.pausedByUserCorrection, isTrue);
      expect(service.isPaused, isFalse);

      service.onUserInteractionEnd();

      expect(service.pausedByUserCorrection, isFalse);
    });

    test('toggle resumes from temporary user yield instead of pausing',
        () async {
      final controller = FractalController(ModuleRegistry());
      controller.resetView();
      controller.updateZoom(1.0);

      final service = AutoExploreService(
        controller: controller,
        config: const AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1),
        ),
      );
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      await Future<void>.delayed(Duration.zero);
      service.onUserInteractionStart();

      expect(service.pausedByUserCorrection, isTrue);
      expect(service.isPaused, isFalse);

      service.toggle();

      expect(service.isExploring, isTrue);
      expect(service.isPaused, isFalse);
      expect(service.pausedByUserCorrection, isFalse);
    });

    test('resume replans from a zoom changed while paused', () async {
      final controller = FractalController(ModuleRegistry());
      controller.resetView();
      controller.updateZoom(1.0);

      final service = AutoExploreService(
        controller: controller,
        config: const AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1),
        ),
      );
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      await Future<void>.delayed(Duration.zero);
      service.pause();

      controller.updateZoom(10.0);
      service.resume();

      await Future<void>.delayed(Duration.zero);
      await Future<void>.delayed(const Duration(milliseconds: 20));

      expect(controller.view.zoom, 1200.0);
    });

    test('ignores unmatched continuous interaction end callbacks', () async {
      final controller = FractalController(ModuleRegistry());
      controller.resetView();
      controller.updateZoom(1.0);

      final service = AutoExploreService(
        controller: controller,
        config: const AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1),
        ),
      );
      addTearDown(service.dispose);
      addTearDown(controller.dispose);

      service.start();
      await Future<void>.delayed(Duration.zero);
      await Future<void>.delayed(const Duration(milliseconds: 20));

      expect(controller.view.zoom, 120.0);

      service.onUserInteractionEnd();
      await Future<void>.delayed(Duration.zero);
      await Future<void>.delayed(const Duration(milliseconds: 20));

      expect(controller.view.zoom, AutoExploreConfig.defaultMinZoom);
    });
  });
}

