(double r, double g, double b) _cpu_eisenstein(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  // Ported from shaders/escape_time_family/polynomial_maps/lattice_wrapped/eisenstein_gpu.frag
  const sqrt3 = 1.7320508075688772;
  final cx = x;
  final cy = y;
  double zx = 0.0;
  double zy = 0.0;

