import 'package:shared_preferences/shared_preferences.dart';
import 'package:flutter_fractals/core/models/fractal_preset.dart';

class PresetStore {
  final SharedPreferences _prefs;

  PresetStore._(this._prefs);

  static Future<PresetStore> create() async {
    final prefs = await SharedPreferences.getInstance();
    return PresetStore._(prefs);
  }

  Future<List<FractalPreset>> loadUserPresets(String moduleId) async {
    final payload = _prefs.getString(_key(moduleId));
    return FractalPreset.listFromPrefs(payload);
  }

  Future<void> saveUserPreset(FractalPreset preset) async {
    final presets = await loadUserPresets(preset.moduleId);
    // Check for duplicate ID and replace if exists
    final existingIndex = presets.indexWhere((p) => p.id == preset.id);
    final List<FractalPreset> updated;
    if (existingIndex >= 0) {
      // Replace existing preset with same ID
      updated = [...presets];
      updated[existingIndex] = preset;
    } else {
      // Add new preset
      updated = [...presets, preset];
    }
    await _prefs.setString(_key(preset.moduleId), FractalPreset.listToPrefs(updated));
  }

  Future<void> deleteUserPreset(String moduleId, String presetId) async {
    final presets = await loadUserPresets(moduleId);
    final updated = presets.where((preset) => preset.id != presetId).toList();
    await _prefs.setString(_key(moduleId), FractalPreset.listToPrefs(updated));
  }

  Future<void> updatePreset(String moduleId, String presetId, {required String name}) async {
    final presets = await loadUserPresets(moduleId);
    final index = presets.indexWhere((p) => p.id == presetId);
    if (index < 0) return;
    final updated = [...presets];
    updated[index] = presets[index].copyWith(name: name);
    await _prefs.setString(_key(moduleId), FractalPreset.listToPrefs(updated));
  }

  String _key(String moduleId) => 'user_presets_$moduleId';
}

import 'package:flutter_test/flutter_test.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:vector_math/vector_math.dart';
import 'package:flutter_fractals/core/services/preset_store.dart';
import 'package:flutter_fractals/core/models/fractal_preset.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';

FractalPreset _makePreset(String id, String moduleId, {String name = 'Test', bool isBuiltIn = false}) {
  return FractalPreset(
    id: id,
    moduleId: moduleId,
    name: name,
    params: {'iterations': 100},
    view: FractalViewState(
      pan: Vector2(0.0, 0.0),
      zoom: 1.0,
      rotation: Vector3.zero(),
    ),
    createdAt: DateTime.utc(2024, 1, 1),
    isBuiltIn: isBuiltIn,
  );
}

void main() {
  group('PresetStore', () {
    setUp(() {
      TestWidgetsFlutterBinding.ensureInitialized();
      SharedPreferences.setMockInitialValues({});
    });

    test('create() factory returns a valid store', () async {
      final store = await PresetStore.create();
      expect(store, isNotNull);
    });

    test('loadUserPresets returns empty list for unknown module', () async {
      final store = await PresetStore.create();
      final presets = await store.loadUserPresets('unknown_module');
      expect(presets, isEmpty);
    });

    test('saveUserPreset persists preset and loadUserPresets returns it', () async {
      final store = await PresetStore.create();
      final preset = _makePreset('p1', 'mandelbrot', name: 'My Preset');

      await store.saveUserPreset(preset);
      final loaded = await store.loadUserPresets('mandelbrot');

      expect(loaded, hasLength(1));
      expect(loaded.first.id, equals('p1'));
      expect(loaded.first.name, equals('My Preset'));
      expect(loaded.first.moduleId, equals('mandelbrot'));
    });

    test('loadUserPresets for a different module returns empty list', () async {
      final store = await PresetStore.create();
      await store.saveUserPreset(_makePreset('p1', 'mandelbrot'));

      final loaded = await store.loadUserPresets('julia');
      expect(loaded, isEmpty);
    });

    test('deleteUserPreset removes the preset', () async {
      final store = await PresetStore.create();
      await store.saveUserPreset(_makePreset('p1', 'mandelbrot'));
      await store.saveUserPreset(_makePreset('p2', 'mandelbrot'));

      await store.deleteUserPreset('mandelbrot', 'p1');
      final loaded = await store.loadUserPresets('mandelbrot');

      expect(loaded, hasLength(1));
      expect(loaded.first.id, equals('p2'));
    });

    test('deleteUserPreset on non-existent id leaves list unchanged', () async {
      final store = await PresetStore.create();
      await store.saveUserPreset(_makePreset('p1', 'mandelbrot'));

      await store.deleteUserPreset('mandelbrot', 'does-not-exist');
      final loaded = await store.loadUserPresets('mandelbrot');

      expect(loaded, hasLength(1));
    });

    test('saveUserPreset replaces preset with same id', () async {
      final store = await PresetStore.create();
      await store.saveUserPreset(_makePreset('p1', 'mandelbrot', name: 'Original'));
      await store.saveUserPreset(_makePreset('p1', 'mandelbrot', name: 'Updated'));

      final loaded = await store.loadUserPresets('mandelbrot');
      expect(loaded, hasLength(1));
      expect(loaded.first.name, equals('Updated'));
    });

    test('user presets are stored separately per module', () async {
      final store = await PresetStore.create();
      await store.saveUserPreset(_makePreset('p1', 'mandelbrot'));
      await store.saveUserPreset(_makePreset('p2', 'julia'));

      final mandelbrot = await store.loadUserPresets('mandelbrot');
      final julia = await store.loadUserPresets('julia');

      expect(mandelbrot, hasLength(1));
      expect(mandelbrot.first.id, equals('p1'));
      expect(julia, hasLength(1));
      expect(julia.first.id, equals('p2'));
    });

    test('user presets are separate from built-in presets (isBuiltIn flag preserved)', () async {
      final store = await PresetStore.create();
      final userPreset = _makePreset('user-1', 'mandelbrot', isBuiltIn: false);
      final builtIn = _makePreset('builtin-1', 'mandelbrot', isBuiltIn: true);

      await store.saveUserPreset(userPreset);
      await store.saveUserPreset(builtIn);

      final loaded = await store.loadUserPresets('mandelbrot');
      expect(loaded, hasLength(2));

      final userLoaded = loaded.firstWhere((p) => p.id == 'user-1');
      final builtInLoaded = loaded.firstWhere((p) => p.id == 'builtin-1');
      expect(userLoaded.isBuiltIn, isFalse);
      expect(builtInLoaded.isBuiltIn, isTrue);
    });

    test('updatePreset renames preset by id', () async {
      final store = await PresetStore.create();
      await store.saveUserPreset(_makePreset('p1', 'mandelbrot', name: 'Old Name'));

      await store.updatePreset('mandelbrot', 'p1', name: 'New Name');
      final loaded = await store.loadUserPresets('mandelbrot');

      expect(loaded.first.name, equals('New Name'));
    });

    test('updatePreset on non-existent id is a no-op', () async {
      final store = await PresetStore.create();
      await store.saveUserPreset(_makePreset('p1', 'mandelbrot', name: 'Original'));

      await store.updatePreset('mandelbrot', 'does-not-exist', name: 'Ghost');
      final loaded = await store.loadUserPresets('mandelbrot');

      expect(loaded.first.name, equals('Original'));
    });
  });
}

import 'dart:convert';
import 'package:flutter/foundation.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:flutter_fractals/features/history/history_entry.dart';

/// Persists exploration history and favorites to local storage.
///
/// History entries are stored in SharedPreferences as JSON.
/// Maintains separate storage for:
/// - Navigation history (limited size, auto-trimmed)
/// - Favorites (unlimited, user-managed)
///
/// {@category Services}
class HistoryStore {
  final SharedPreferences _prefs;

  static const String _historyKey = 'exploration_history';
  static const String _favoritesKey = 'exploration_favorites';
  static const int maxHistoryEntries = 100;
  static const int maxFavoriteEntries = 500;

  HistoryStore._(this._prefs);

  /// Creates a new [HistoryStore] instance.
  static Future<HistoryStore> create() async {
    final prefs = await SharedPreferences.getInstance();
    return HistoryStore._(prefs);
  }

  /// Loads the navigation history.
  ///
  /// Returns entries in chronological order (oldest first).
  List<HistoryEntry> loadHistory() => _loadEntries(_historySlot);

  /// Saves the navigation history.
  ///
  /// Automatically trims to [maxHistoryEntries].
  Future<void> saveHistory(List<HistoryEntry> entries) async {
    await _saveEntries(_historySlot, entries);
  }

  /// Loads the user's favorite locations.
  List<HistoryEntry> loadFavorites() => _loadEntries(_favoritesSlot);

  /// Saves the user's favorite locations.
  ///
  /// Capped at [maxFavoriteEntries] to prevent unbounded storage growth.
  Future<void> saveFavorites(List<HistoryEntry> favorites) async {
    await _saveEntries(_favoritesSlot, favorites);
  }

  /// Adds an entry to favorites.
  Future<void> addFavorite(HistoryEntry entry) async {
    final favorites = loadFavorites();
    // Check if already exists by ID
    if (favorites.any((f) => f.id == entry.id)) return;
    favorites.add(entry);
    await saveFavorites(favorites);
  }

  /// Removes an entry from favorites by ID.
  Future<void> removeFavorite(String entryId) async {
    final favorites = loadFavorites();
    final updated = favorites.where((f) => f.id != entryId).toList();
    await saveFavorites(updated);
  }

  /// Clears all navigation history.
  Future<void> clearHistory() async {
    await _prefs.remove(_historyKey);
  }

  /// Clears all favorites.
  Future<void> clearFavorites() async {
    await _prefs.remove(_favoritesKey);
  }

  List<HistoryEntry> _loadEntries(_HistoryStoreSlot slot) {
    final payload = _prefs.getString(slot.key);
    return _HistoryEntryCodec.parse(payload, slotLabel: slot.label);
  }

  Future<void> _saveEntries(
    _HistoryStoreSlot slot,
    List<HistoryEntry> entries,
  ) async {
    final bounded = slot.mostRecent(entries);
    await _prefs.setString(slot.key, _HistoryEntryCodec.serialize(bounded));
  }
}

const _historySlot = _HistoryStoreSlot(
  key: HistoryStore._historyKey,
  label: 'history',
  maxEntries: HistoryStore.maxHistoryEntries,
);

const _favoritesSlot = _HistoryStoreSlot(
  key: HistoryStore._favoritesKey,
  label: 'favorites',
  maxEntries: HistoryStore.maxFavoriteEntries,
);

/// Storage contract for one SharedPreferences-backed history collection.
///
/// Entries are expected oldest-first. When a slot exceeds its cap, the oldest
/// entries are dropped and the most recent tail is retained.
class _HistoryStoreSlot {
  final String key;
  final String label;
  final int maxEntries;

  const _HistoryStoreSlot({
    required this.key,
    required this.label,
    required this.maxEntries,
  }) : assert(maxEntries > 0);

  List<HistoryEntry> mostRecent(List<HistoryEntry> entries) {
    if (entries.length <= maxEntries) return entries;
    return entries.sublist(entries.length - maxEntries);
  }
}

class _HistoryEntryCodec {
  const _HistoryEntryCodec._();

  static List<HistoryEntry> parse(String? payload,
      {required String slotLabel}) {
    if (payload == null || payload.isEmpty) return [];
    try {
      final decoded = jsonDecode(payload) as List;
      final entries = <HistoryEntry>[];
      for (final item in decoded) {
        try {
          final entry =
              HistoryEntry.fromJson((item as Map).cast<String, Object?>());
          entries.add(entry);
        } catch (e) {
          // Skip corrupted entry, continue with others.
          if (kDebugMode) {
            debugPrint('Failed to parse $slotLabel entry: $e');
          }
        }
      }
      return entries;
    } catch (e) {
      // Corrupted JSON, return empty list.
      if (kDebugMode) debugPrint('Failed to parse $slotLabel JSON: $e');
      return [];
    }
  }

  static String serialize(List<HistoryEntry> entries) {
    return jsonEncode(entries.map((e) => e.toJson()).toList());
  }
}

import 'package:flutter_test/flutter_test.dart';
import 'package:shared_preferences/shared_preferences.dart';
