/// Replayable kaleidoscope effect state owned by [FractalController].
///
/// Some catalog modules are kaleidoscope-specific and temporarily force the
/// global kaleidoscope canvas effect on with module defaults. Keeping the
/// previous user-controlled effect state separate from the forced module state
/// prevents module switches from leaking kaleidoscope settings into unrelated
/// fractals.
final class FractalKaleidoscopeState {
  static const int defaultSectors = 8;
  static const int forcedModuleSectors = 16;
  static const int defaultMirrorMode = 0;
  static const int forcedModuleMirrorMode = 3;

  final bool enabled;
  final int sectors;
  final bool mirror;
  final double rotation;
  final int mirrorMode;

  const FractalKaleidoscopeState({
    required this.enabled,
    required this.sectors,
    required this.mirror,
    required this.rotation,
    required this.mirrorMode,
  });

  const FractalKaleidoscopeState.defaults()
      : enabled = false,
        sectors = defaultSectors,
        mirror = true,
        rotation = 0.0,
        mirrorMode = defaultMirrorMode;

  FractalKaleidoscopeState copyWith({
    bool? enabled,
    int? sectors,
    bool? mirror,
    double? rotation,
    int? mirrorMode,
  }) {
    return FractalKaleidoscopeState(
      enabled: enabled ?? this.enabled,
      sectors: sectors ?? this.sectors,
      mirror: mirror ?? this.mirror,
      rotation: rotation ?? this.rotation,
      mirrorMode: mirrorMode ?? this.mirrorMode,
    );
  }
}

/// Result of applying module-specific kaleidoscope defaults.
final class FractalKaleidoscopeModuleTransition {
  final FractalKaleidoscopeState effective;
  final FractalKaleidoscopeState? restoreAfterForcedModule;

  const FractalKaleidoscopeModuleTransition({
    required this.effective,
    required this.restoreAfterForcedModule,
  });
}

/// Pure module-switch policy for kaleidoscope-specific catalog modules.
final class FractalKaleidoscopeModulePolicy {
  const FractalKaleidoscopeModulePolicy._();

  static bool isForcedModuleId(String moduleId) =>
      moduleId.contains('kaleidoscope');

  static FractalKaleidoscopeModuleTransition transitionForModule({
    required String moduleId,
    required FractalKaleidoscopeState current,
    required FractalKaleidoscopeState? restoreAfterForcedModule,
  }) {
    if (isForcedModuleId(moduleId)) {
      return FractalKaleidoscopeModuleTransition(
        effective: current.copyWith(
          enabled: true,
          sectors: FractalKaleidoscopeState.forcedModuleSectors,
          mirrorMode: FractalKaleidoscopeState.forcedModuleMirrorMode,
        ),
        restoreAfterForcedModule: restoreAfterForcedModule ?? current,
      );
    }

    if (restoreAfterForcedModule != null) {
      return FractalKaleidoscopeModuleTransition(
        effective: restoreAfterForcedModule,
        restoreAfterForcedModule: null,
      );
    }

    return FractalKaleidoscopeModuleTransition(
      effective: current,
      restoreAfterForcedModule: null,
    );
  }
}

import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('FractalController effect input bounds', () {
    test('preserves glow settings when replayed values are NaN', () {
      final controller = FractalController(ModuleRegistry());
      addTearDown(controller.dispose);

      controller.setGlowSigma(2.5);
      controller.setGlowIntensity(0.6);

      controller.setGlowSigma(double.nan);
      controller.setGlowIntensity(double.nan);

      expect(controller.glowSigma, 2.5);
      expect(controller.glowIntensity, 0.6);
    });

    test('preserves kaleidoscope rotation when replayed values are non-finite',
        () {
      final controller = FractalController(ModuleRegistry());
      addTearDown(controller.dispose);

      controller.setKaleidoscopeRotation(0.75);

      controller.setKaleidoscopeRotation(double.nan);
      expect(controller.kaleidoscopeRotation, 0.75);

      controller.setKaleidoscopeRotation(double.infinity);
      expect(controller.kaleidoscopeRotation, 0.75);
    });

    test('does not leak forced kaleidoscope defaults after module exit', () {
      final registry = ModuleRegistry();
      final controller = FractalController(registry);
      addTearDown(controller.dispose);

      final normalModule = registry.byId('mandelbrot');
      final kaleidoscopeModule = registry.byId('kaleidoscope_basic');

      controller.selectModule(normalModule, animate: false);
      controller.setKaleidoscopeEnabled(false);
      controller.setKaleidoscopeSectors(6);
      controller.setKaleidoscopeMirrorMode(1);

      controller.selectModule(kaleidoscopeModule, animate: false);

      expect(controller.kaleidoscopeEnabled, isTrue);
      expect(controller.kaleidoscopeSectors, 16);
      expect(controller.kaleidoscopeMirrorMode, 3);

      controller.selectModule(normalModule, animate: false);

      expect(controller.kaleidoscopeEnabled, isFalse);
      expect(controller.kaleidoscopeSectors, 6);
      expect(controller.kaleidoscopeMirrorMode, 1);
    });
  });
}

  /// The currently selected fractal module (alias for [module]).
  FractalModule get currentModule => _module;

  /// Loads a complete state from another controller or snapshot.
  ///
  /// This initializes the controller from a full state including
  /// module, parameters, view state, and transparency setting.
  /// Parameters are clamped to the target module's schema.
  ///
  /// Can accept either a [module] object directly or a [moduleId] string.
  void loadState({
    FractalModule? module,
    String? moduleId,
    required Map<String, Object> params,
    required FractalViewState view,
    bool transparentBackground = false,
    bool animateModule = false,
  }) {
    // Find the module by ID or use provided module
    final FractalModule targetModule;
    if (module != null) {
      targetModule = module;
    } else if (moduleId != null) {
      targetModule = registry.modules.firstWhere(
        (m) => m.id == moduleId,
        orElse: () => _module,
      );
    } else {
      targetModule = _module;
    }

    // Switch to the target module
    if (targetModule.id != _module.id) {
      if (animateModule) {
        selectModule(targetModule, animate: true);
      } else {
        _module = targetModule;
      }
    }

    _applyKaleidoscopeModulePolicy(_module.id);

    // Apply parameters with clamping
    final clamped = <String, Object>{};
    for (final param in _module.parameters) {
      final value = params[param.id] ?? param.defaultValue;
      clamped[param.id] = normalizeFractalParamValue(param, value);
    }
    _params = clamped;

    // Set view state
    _view = FractalViewInputBounds.normalizeView(
      candidate: view,
      current: _view,
      moduleId: _module.id,
    );
    _lastAdaptiveZoom = _view.zoom;

    // Set transparency
    _transparentBackground = transparentBackground;

    notifyListeners();
    _logChange('stateChange', 'loadState', 'Loaded state for ${_module.id}');
  }
}

